css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: 'Georgia', 'Times New Roman', serif; background: #120b07; color: #f5e6d3; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 80px; border-bottom: 1px solid rgba(245,182,93,0.15); }
.logo { font-size: 22px; font-weight: 700; color: #f5b65d; }
.links { display: flex; gap: 32px; } .links a { color: #a08060; text-decoration: none; font-size: 15px; letter-spacing: 1px; transition: color 0.2s; } .links a:hover { color: #f5b65d; }
.reserve { padding: 12px 24px; border-radius: 4px; border: 1px solid #f5b65d; background: transparent; color: #f5b65d; font-weight: 600; cursor: pointer; letter-spacing: 1px; transition: all 0.3s; } .reserve:hover { background: #f5b65d; color: #120b07; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 72px; min-height: calc(100vh - 80px); }
.tag { display: inline-block; color: #f5b65d; font-size: 13px; letter-spacing: 3px; margin-bottom: 24px; }
h1 { font-size: 72px; font-weight: 700; line-height: 1; margin-bottom: 24px; color: #f5e6d3; } h1 span { color: #f5b65d; }
.hero-content p { color: #a08060; font-size: 17px; line-height: 1.8; margin-bottom: 36px; max-width: 440px; }
.hero-btns { display: flex; gap: 16px; margin-bottom: 28px; }
.btn-res { padding: 16px 32px; border-radius: 4px; border: none; background: #f5b65d; color: #120b07; font-weight: 700; font-size: 15px; cursor: pointer; }
.btn-menu { padding: 16px 32px; border-radius: 4px; border: 1px solid rgba(245,182,93,0.3); background: transparent; color: #f5b65d; font-weight: 600; font-size: 15px; cursor: pointer; }
.open-info { color: #6b5040; font-size: 13px; }
.hero-img { position: relative; height: 500px; }
.food-card { position: absolute; background: rgba(30,18,10,0.95); border: 1px solid rgba(245,182,93,0.2); border-radius: 16px; padding: 20px; backdrop-filter: blur(10px); }
.food-card.main { width: 280px; bottom: 40px; left: 0; display: flex; gap: 16px; align-items: center; }
.food-img { font-size: 48px; } .food-img.sm { font-size: 28px; }
.food-info strong { display: block; font-size: 16px; margin-bottom: 4px; } .food-info span { color: #a08060; font-size: 13px; } .food-price { color: #f5b65d; font-size: 18px; font-weight: 700; margin-top: 8px; }
.food-card.small { display: flex; align-items: center; gap: 12px; } .food-card.small strong { display: block; font-size: 14px; } .food-card.small span { color: #f5b65d; font-size: 13px; font-weight: 700; }
.food-card.top { top: 60px; right: 0; } .food-card.bottom { top: 220px; right: 20px; }
.menu-preview { padding: 80px 72px; border-top: 1px solid rgba(245,182,93,0.1); }
.menu-preview h2 { font-size: 42px; margin-bottom: 40px; color: #f5e6d3; }
.menu-grid { display: flex; flex-direction: column; gap: 0; }
.menu-item { display: flex; align-items: center; gap: 20px; padding: 24px 0; border-bottom: 1px solid rgba(245,182,93,0.08); }
.menu-emoji { font-size: 32px; width: 52px; text-align: center; }
.menu-item div strong { display: block; font-size: 18px; margin-bottom: 4px; } .menu-item div p { color: #a08060; font-size: 14px; }
.price { margin-left: auto; color: #f5b65d; font-size: 20px; font-weight: 700; font-family: sans-serif; }
